"""Safely verify the CodeParrot dataset using streaming."""

from itertools import islice
from typing import Any

from datasets import IterableDataset, load_dataset

DATASET_ID = "codeparrot/codeparrot-clean"
SPLIT = "train"
SAMPLE_LIMIT = 3

EXPECTED_FIELDS = {
    "repo_name",
    "path",
    "copies",
    "size",
    "content",
    "license",
    "hash",
    "line_mean",
    "line_max",
    "alpha_frac",
    "autogenerated",
}


def safe_text(value: Any) -> str:
    """Return a short printable value without exposing source code."""
    if value is None:
        return "<missing>"

    text = str(value)
    return text if len(text) <= 80 else f"{text[:77]}..."


def main() -> None:
    """Verify streaming, schema, and limited metadata."""
    print(f"Dataset: {DATASET_ID}")
    print(f"Split: {SPLIT}")
    print(f"Sample limit: {SAMPLE_LIMIT}")
    print("Loading mode: streaming")

    dataset = load_dataset(
        DATASET_ID,
        split=SPLIT,
        streaming=True,
    )

    if not isinstance(dataset, IterableDataset):
        raise TypeError(
            "Expected an IterableDataset. The dataset may not be streaming."
        )

    print(f"Dataset type: {type(dataset).__name__}")

    observed_fields: set[str] = set()
    sample_count = 0

    for index, sample in enumerate(islice(dataset, SAMPLE_LIMIT), start=1):
        sample_count += 1
        observed_fields.update(sample)

        content = sample.get("content")
        content_length = len(content) if isinstance(content, str) else 0

        print(f"\nSample {index}")
        print(f"  repository: {safe_text(sample.get('repo_name'))}")
        print(f"  path: {safe_text(sample.get('path'))}")
        print(f"  license: {safe_text(sample.get('license'))}")
        print(f"  declared size: {safe_text(sample.get('size'))}")
        print(f"  content characters: {content_length}")
        print(f"  autogenerated: {safe_text(sample.get('autogenerated'))}")

    missing_fields = EXPECTED_FIELDS - observed_fields
    extra_fields = observed_fields - EXPECTED_FIELDS

    print("\nVerification summary")
    print(f"  samples inspected: {sample_count}")
    print(f"  observed fields: {sorted(observed_fields)}")
    print(f"  missing expected fields: {sorted(missing_fields)}")
    print(f"  additional fields: {sorted(extra_fields)}")

    if sample_count != SAMPLE_LIMIT:
        raise RuntimeError(
            f"Expected {SAMPLE_LIMIT} samples, received {sample_count}."
        )

    if "content" not in observed_fields:
        raise RuntimeError("Required field 'content' was not found.")

    print("  streaming verification: PASSED")


if __name__ == "__main__":
    main()